use std::cmp::Ordering;
use std::io;

#[derive(Debug, PartialEq, Eq)]
pub enum Outcome { TooSmall, TooBig, Win }

/// Pure helper extracted from the loop body so tests can exercise the
/// comparison branches without touching stdin or the rng.
pub fn decide(guess: u32, secret: u32) -> Outcome {
    match guess.cmp(&secret) {
        Ordering::Less => Outcome::TooSmall,
        Ordering::Greater => Outcome::TooBig,
        Ordering::Equal => Outcome::Win,
    }
}

fn main() {
    println!("Guess the number!");

    let secret_number: u32 = rand::random_range(1..=100);

    [[SLOT loop_kw]]
        println!("Please input your guess.");

        let mut guess = String::new();

        io::stdin()
            .read_line(&mut guess)
            .expect("Failed to read line");

        let guess: u32 = match guess.trim().parse() {
            [[SLOT ok_arm]]
            [[SLOT err_arm]]
        };

        println!("You guessed: {guess}");

        match decide(guess, secret_number) {
            Outcome::TooSmall => println!("Too small!"),
            Outcome::TooBig => println!("Too big!"),
            Outcome::Win => {
                println!("You win!");
                [[SLOT break_stmt]]
            }
        }
    }
}
